import { MakeLogicType, actions, defaults, kea, listeners, path, reducers, selectors } from 'kea'
import { loaders } from 'kea-loaders'

import api, { CountedPaginatedResponse } from 'lib/api'
import { ErrorTrackingRelease } from 'lib/components/Errors/types'
import { Scene } from 'scenes/sceneTypes'
import { urls } from 'scenes/urls'

import { Breadcrumb } from '~/types'


export const RESULTS_PER_PAGE = 20

export type ErrorTrackingReleaseResponse = CountedPaginatedResponse<ErrorTrackingRelease>

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface releasesLogicValues {
    breadcrumbs: Breadcrumb[];
    page: number;
    pagination: {
        controlled: true;
        currentPage: number;
        entryCount: number;
        onBackward: () => void;
        onForward: () => void;
        pageSize: number;
    };
    releaseResponse: ErrorTrackingReleaseResponse | null;
    releaseResponseLoading: boolean;
    releases: ErrorTrackingRelease[];
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface releasesLogicActions {
    loadReleases: () => void;
    loadReleasesFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    loadReleasesSuccess: (releaseResponse: CountedPaginatedResponse<ErrorTrackingRelease>, payload?: void) => {
        releaseResponse: CountedPaginatedResponse<ErrorTrackingRelease>;
        payload?: void;
    };
    setPage: (page: number) => {
        page: number;
    };
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface releasesLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        releases: (releaseResponse: ErrorTrackingReleaseResponse | null) => ErrorTrackingRelease[];
        pagination: (page: number, releaseResponse: ErrorTrackingReleaseResponse | null) => {
            controlled: true;
            currentPage: number;
            entryCount: number;
            onBackward: () => void;
            onForward: () => void;
            pageSize: number;
        };
    };
}

export type releasesLogicType = MakeLogicType<releasesLogicValues, releasesLogicActions, Record<string, any>, releasesLogicMeta>;

export const releasesLogic = kea<releasesLogicType>([
    path(['products', 'error_tracking', 'scenes', 'ErrorTrackingConfigurationScene', 'releases', 'releasesLogic']),

    actions({
        loadReleases: () => {},
        setPage: (page: number) => ({ page }),
    }),

    defaults({
        page: 1 as number,
        releaseResponse: null as ErrorTrackingReleaseResponse | null,
    }),

    reducers({
        page: {
            setPage: (_, { page }) => page,
        },
    }),

    listeners(({ actions }) => ({
        setPage: () => actions.loadReleases(),
    })),

    loaders(({ values }) => ({
        releaseResponse: {
            loadReleases: async (_, breakpoint) => {
                await breakpoint(100)
                const res = await api.errorTracking.releases.list({
                    limit: RESULTS_PER_PAGE,
                    offset: (values.page - 1) * RESULTS_PER_PAGE,
                })
                return res
            },
        },
    })),

    selectors(({ actions }) => ({
        breadcrumbs: [
            () => [],
            (): Breadcrumb[] => [
                {
                    key: Scene.ErrorTracking,
                    name: 'Error tracking',
                    path: urls.errorTracking(),
                    iconType: 'error_tracking',
                },
                {
                    key: 'error-tracking-configuration',
                    name: 'Configuration',
                    iconType: 'error_tracking',
                },
            ],
        ],
        releases: [
            (s) => [s.releaseResponse],
            (response: ErrorTrackingReleaseResponse): ErrorTrackingRelease[] => {
                return response?.results || []
            },
        ],
        pagination: [
            (s) => [s.page, s.releaseResponse],
            (page: number, releaseResponse: ErrorTrackingReleaseResponse) => {
                return {
                    controlled: true,
                    pageSize: RESULTS_PER_PAGE,
                    currentPage: page,
                    entryCount: releaseResponse?.count ?? 0,
                    onBackward: () => actions.setPage(page - 1),
                    onForward: () => actions.setPage(page + 1),
                }
            },
        ],
    })),
])
